using System;
using Supprocom.NativeAllocationManagement;
public sealed class DisposableThing : IDisposable { public void Dispose() { } }
public static class Sample { public static void Run() { using (new DisposableThing()) { NativeRegion region = new(); NativePool<int> pool = new(returnOnDispose: NativeReturn.ToNativeMemory); Pooled<int> value = pool.Rent(1); } } }

using System;
using Supprocom.NativeAllocationManagement;
public sealed class Sample : IDisposable { private readonly NativePool<int> _pool = new(returnOnDispose: NativeReturn.ToNativeMemory); private readonly NativePool<int> _other = new(); public void Dispose() { _other.Dispose(); } }

using Supprocom.NativeAllocationManagement;
public record Holder(NativePool<int> Pool);
public static class Sample { public static void Run() { NativePool<int> pool = new(); Holder holder = new(pool); pool.Dispose(); } }

using Supprocom.NativeAllocationManagement;
public sealed class Holder<T> { public T Value = default!; }
public static class Sample { public static void Run() { NativePool<int> pool = new(); Holder<NativePool<int>> holder = new() { Value = pool }; pool.Dispose(); } }

using Supprocom.NativeAllocationManagement;
public sealed class Holder<T> { public T Value = default!; }
public static class Sample { public static void Run() { NativePool<int> pool = new(); Pooled<int> value = pool.Rent(1); Holder<Pooled<int>> holder = new(); holder.Value = value; } }

using System;
using Supprocom.NativeAllocationManagement;
public static class Sample { public static void Run() { NativePool<int> pool = new(); Pooled<int> value = pool.Rent(1); Action callback = () => Console.WriteLine(value.Length); } }

using System.Threading.Tasks;
using Supprocom.NativeAllocationManagement;
public static class Sample { public static async Task Run() { NativePool<int> pool = new(); Pooled<int> value = pool.Rent(1); await Task.Yield(); _ = value.Length; } }

using System.Collections.Generic;
using Supprocom.NativeAllocationManagement;
public static class Sample { public static IEnumerable<int> Run() { NativePool<int> pool = new(); Pooled<int> value = pool.Rent(1); yield return value.Length; } }
